#include <bits/stdc++.h>
using namespace std;
int a[10]={6,2,5,5,4,5,6,3,7,6};
int match(int x){
    if(x==0)
        return a[0];
    int sum=0;
    while(x){
        sum+=a[x%10];
        x/=10;
    }
    return sum;
}
int main(){
    int n,ans=0;
    scanf("%d",&n);
    for(int a=0;a<=1000;a++)
        for(int b=0;b<=1000;b++)
            if(match(a)+match(b)+match(a+b)+4==n)
                ans++;
    printf("%d",ans);
    return 0;
}
